function ask(question) {
  return new Promise((resolve) => {
    const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
    rl.question(question, (answer) => {
      rl.close();
      resolve(answer.trim());
    });
  });
}

async function run() {
  const app = initializeApp(firebaseConfig);
  const auth = getAuth(app);
  const db = getDatabase(app);

  console.log("=== Admin Login Required ===");
  const email = await ask("Admin email: ");
  const password = await ask("Admin password: ");

  try {
    const cred = await signInWithEmailAndPassword(auth, email, password);
    console.log("✅ Logged in as:", email, "| uid:", cred.user.uid);
    await new Promise(resolve => setTimeout(resolve, 2000));
    console.log("TOKEN:", await cred.user.getIdToken());
  } catch (e) {
    console.error("❌ Login failed:", e.message);
    process.exit(1);
  }

  try {
    console.log(`\nWriting ${Object.keys(CATEGORIES).length} categories...`);
    await set(ref(db, "categories"), CATEGORIES);
    console.log("✅ Categories imported successfully");
  } catch (e) {
    console.error("❌ Categories import failed:", e.message);
    console.error("   -> Make sure your account has role='admin' set in /users/{your-uid}/role");
    console.error("      and that the new Realtime Database Rules have been published.");
    process.exit(1);
  }

  try {
    console.log(`\nWriting ${Object.keys(PRODUCTS).length} products...`);
    await update(ref(db, "products"), PRODUCTS);
    console.log("✅ Products imported successfully");
  } catch (e) {
    console.error("❌ Products import failed:", e.message);
    process.exit(1);
  }

  console.log("\n🚀 DONE: All data imported to Firebase RTDB");
  process.exit(0);
}

run();
